  1→// ─── Shared List Navigation Styles ────────────────────────────────────────────
  2→.nav-list {
  3→    flex: 1;
  4→    overflow-y: auto;
  5→    padding: 0 8px 12px;
  6→    display: flex;
  7→    flex-direction: column;
  8→    gap: 2px;
  9→}
 10→
 11→.nav-item {
 12→    position: relative;
 13→    width: 100%;
 14→    display: flex;
 15→    align-items: center;
 16→    gap: 10px;
 17→    padding: 6px 4px;
 18→    border: 1px solid transparent;
 19→    border-radius: 10px;
 20→    background: transparent;
 21→    color: var(--mat-sys-on-surface-variant);
 22→    text-align: left;
 23→    text-decoration: none;
 24→    cursor: pointer;
 25→    font-size: 0.875rem;
 26→    font-weight: 500;
 27→    box-sizing: border-box;
 28→    transition:
 29→        background 0.15s ease,
 30→        color 0.15s ease,
 31→        border-color 0.15s ease,
 32→        box-shadow 0.18s ease,
 33→        transform 0.18s ease;
 34→
 35→    mat-icon {
 36→        font-size: 18px;
 37→        width: 18px;
 38→        height: 18px;
 39→        flex-shrink: 0;
 40→    }
 41→
 42→    span,
 43→    .nav-item-label {
 44→        line-height: 1.2;
 45→        white-space: nowrap;
 46→        overflow: hidden;
 47→        text-overflow: ellipsis;
 48→        flex: 1;
 49→        min-width: 0;
 50→        padding-left: 10px;
 51→    }
 52→
 53→    .nav-item-meta {
 54→        font-size: 0.8rem;
 55→        min-width: 2ch;
 56→        text-align: right;
 57→        flex-shrink: 0;
 58→        color: var(--mat-sys-on-surface-variant);
 59→        opacity: 0.7;
 60→    }
 61→
 62→    &:hover:not(.selected):not(.active):not(.is-active) {
 63→        background: var(--app-selection-surface);
 64→        color: var(--mat-sys-on-surface);
 65→    }
 66→
 67→    &.selected,
 68→    &.active,
 69→    &.is-active {
 70→        background: linear-gradient(
 71→            135deg,
 72→            var(--app-selection-surface-strong),
 73→            var(--app-selection-surface)
 74→        ) !important;
 75→        color: var(--app-selection-color) !important;
 76→        border-color: var(--app-selection-border) !important;
 77→        font-weight: 600;
 78→        box-shadow:
 79→            inset 0 0 0 1px var(--app-selection-border),
 80→            0 12px 20px -18px var(--app-selection-glow);
 81→        transform: translateY(-1px);
 82→
 83→        * {
 84→            color: var(--app-selection-color) !important;
 85→        }
 86→
 87→        .nav-item-meta {
 88→            color: var(--app-selection-color) !important;
 89→            opacity: 0.92;
 90→        }
 91→
 92→        /* &::before {
 93→            content: '';
 94→            position: absolute;
 95→            inset-inline-start: 2px;
 96→            top: 7px;
 97→            bottom: 7px;
 98→            width: 2px;
 99→            border-radius: 999px;
100→            background: var(--app-selection-color);
101→            box-shadow: 0 0 10px var(--app-selection-glow);
102→        } */
103→    }
104→}
