  3→    effect,
  4→    inject,
  5→    input,
  6→    output,
  7→    viewChild,
  8→} from '@angular/core';
  9→import { toSignal } from '@angular/core/rxjs-interop';
 10→import { MatButtonModule } from '@angular/material/button';
 11→import { MatIconModule } from '@angular/material/icon';
 12→import { MatMenu, MatMenuModule, MatMenuTrigger } from '@angular/material/menu';
 13→import { Store } from '@ngrx/store';
 14→import { TranslateModule } from '@ngx-translate/core';
 15→import { FilterActions, selectActiveTypeFilters } from 'm3u-state';
 16→import { SortBy, SortOrder, SortService } from 'services';
 17→
 18→@Component({
 19→    selector: 'app-filter-sort-menu',
 20→    templateUrl: './filter-sort-menu.component.html',
 21→    styleUrls: ['./filter-sort-menu.component.scss'],
 22→    imports: [MatButtonModule, MatIconModule, MatMenuModule, TranslateModule],
 23→})
 24→export class FilterSortMenuComponent {
 25→    private readonly store = inject(Store);
 26→    private readonly sortService = inject(SortService);
 27→
 28→    readonly menu = viewChild.required<MatMenu>('filterSortMenu');
 29→    readonly menuTrigger = input<MatMenuTrigger>();
 30→    readonly filterChanged = output<void>();
 31→
 32→    playlistTypes = [
 33→        {
 34→            id: 'm3u',
 35→            icon: 'playlist_play',
 36→            translationKey: 'HOME.PLAYLIST_TYPES.M3U',
 37→            checked: true,
 38→        },
 39→        {
 40→            id: 'xtream',
 41→            icon: 'cloud',
 42→            translationKey: 'HOME.PLAYLIST_TYPES.XTREAM',
 43→            checked: true,
 44→        },
 45→        {
 46→            id: 'stalker',
 47→            icon: 'router',
 48→            translationKey: 'HOME.PLAYLIST_TYPES.STALKER',
 49→            checked: true,
 50→        },
 51→    ];
 52→
 53→    private readonly selectedTypeFilters = this.store.selectSignal(
 54→        selectActiveTypeFilters
 55→    );
 56→
 57→    readonly SortBy = SortBy;
 58→    readonly SortOrder = SortOrder;
 59→    private readonly currentSortOptions = toSignal(
 60→        this.sortService.getSortOptions(),
 61→        {
 62→            requireSync: true,
 63→        }
 64→    );
 65→
 66→    constructor() {
 67→        effect(() => {
 68→            if (this.selectedTypeFilters) {
 69→                this.playlistTypes = this.playlistTypes.map((type) => {
 70→                    type.checked = this.selectedTypeFilters().includes(type.id);
 71→                    return type;
 72→                });
 73→            }
 74→        });
 75→    }
 76→
 77→    togglePlaylistType(type: {
 78→        id: string;
 79→        icon: string;
 80→        translationKey: string;
 81→        checked: boolean;
 82→    }) {
 83→        const currentlySelectedCount = this.playlistTypes.filter(
 84→            (item) => item.checked
 85→        ).length;
 86→
 87→        if (type.checked && currentlySelectedCount === 1) {
 88→            return;
 89→        }
 90→
 91→        type.checked = !type.checked;
 92→        this.store.dispatch(
 93→            FilterActions.setSelectedFilters({
 94→                selectedFilters: this.playlistTypes
 95→                    .filter((item) => item.checked)
 96→                    .map((item) => item.id),
 97→            })
 98→        );
 99→        this.filterChanged.emit();
100→    }
101→
102→    setSortOptions(by: SortBy, order: SortOrder): void {
103→        this.sortService.setSortOptions({ by, order });
104→    }
105→
106→    isSortActive(by: SortBy, order: SortOrder): boolean {
107→        const options = this.currentSortOptions();
108→        return options?.by === by && options?.order === order;
109→    }
110→
111→    get activeFiltersCount(): number {
112→        return this.playlistTypes.filter((type) => !type.checked).length;
113→    }
114→
115→    closeMenu(): void {
116→        this.menuTrigger()?.closeMenu();
117→    }
118→}
