  8→// ─── Typography ─────────────────────────────────────────────────────────────
  9→$my-typography: mat.m2-define-typography-config(
 10→    $font-family: "'DM Sans', 'Inter', sans-serif",
 11→);
 12→@include mat.typography-hierarchy($my-typography);
 13→
 14→// ─── M3 Themes ───────────────────────────────────────────────────────────────
 15→$light-theme: mat.define-theme(
 16→    (
 17→        color: (
 18→            theme-type: light,
 19→            primary: mat.$violet-palette,
 20→            tertiary: mat.$cyan-palette,
 21→        ),
 22→        typography: (
 23→            plain-family: "'DM Sans', 'Inter', sans-serif",
 24→            brand-family: "'DM Sans', 'Inter', sans-serif",
 25→        ),
 26→    )
 27→);
 28→
 29→$dark-theme: mat.define-theme(
 30→    (
 31→        color: (
 32→            theme-type: dark,
 33→            primary: mat.$violet-palette,
 34→            tertiary: mat.$cyan-palette,
 35→        ),
 36→        typography: (
 37→            plain-family: "'DM Sans', 'Inter', sans-serif",
 38→            brand-family: "'DM Sans', 'Inter', sans-serif",
 39→        ),
 40→    )
 41→);
 42→
 43→// ─── Apply Themes ────────────────────────────────────────────────────────────
 44→html {
 45→    @include mat.all-component-themes($light-theme);
 46→
 47→    // ── Light theme design tokens ─────────────────────────────────────────
 48→    --app-shell-bg: #eef0f3;
 49→    --app-rail-bg: #e8eaed;
 50→    --app-header-bg: #eef0f3;
 51→    --app-content-bg: #f5f6f8;
 52→    --app-rail-border: rgba(0, 0, 0, 0.08);
 53→    --app-search-bg: rgba(255, 255, 255, 0.7);
 54→    --app-search-border: rgba(0, 0, 0, 0.1);
 55→    --app-selection-color: #2f7bff;
 56→    --app-selection-on-color: #eef4ff;
 57→    --app-selection-surface: color-mix(
 58→        in srgb,
 59→        var(--app-selection-color) 14%,
 60→        transparent
 61→    );
 62→    --app-selection-surface-strong: color-mix(
 63→        in srgb,
 64→        var(--app-selection-color) 22%,
 65→        transparent
 66→    );
 67→    --app-selection-border: color-mix(
 68→        in srgb,
 69→        var(--app-selection-color) 52%,
 70→        transparent
 71→    );
 72→    --app-selection-glow: color-mix(
 73→        in srgb,
 74→        var(--app-selection-color) 34%,
 75→        transparent
 76→    );
 77→
 78→    // Widget surfaces — no borders, layered backgrounds
 79→    --app-widget-bg: #ffffff;
 80→    --app-widget-header-bg: #fafbfc;
 81→    --app-widget-border: transparent;
 82→    --app-widget-shadow: 0 1px 3px rgba(0, 0, 0, 0.06), 0 4px 12px rgba(0, 0, 0, 0.04);
 83→    --app-widget-header-border: rgba(0, 0, 0, 0.06);
 84→    --app-card-hover-bg: #f0f2f5;
 85→    --app-separator: rgba(0, 0, 0, 0.14);
 86→
 87→    // Typography — subdued, not pure black
 88→    --app-heading-color: #1a1d23;
 89→    --app-body-color: #4a5060;
 90→    --app-muted-color: #8891a4;
 91→    --app-eyebrow-color: #7c8495;
 92→
 93→    // Provider accent colors
 94→    --app-provider-xtream: #6366f1;
 95→    --app-provider-stalker: #10b981;
 96→    --app-provider-m3u: #d97706;
 97→
 98→    // Hero
 99→    --app-accent-gradient: linear-gradient(
100→        135deg,
101→        rgba(99, 102, 241, 0.08) 0%,
102→        rgba(168, 85, 247, 0.05) 100%
103→    );
104→    --app-hero-surface: rgba(99, 102, 241, 0.04);
105→
106→    .dark-theme {
107→        @include mat.all-component-colors($dark-theme);
108→
109→        // ── Dark graphite theme ────────────────────────────────────────────
110→        // Inspired by both Slack (sidebar distinction) and GitButler (data density)
111→        // Key principle: clearly distinct surface layers using graphite steps
112→        // Darkest → lightest: #0d0f12 → #141720 → #1c2030 → #222840
113→
114→        // App shell & navigation
115→        --app-shell-bg: #0d0f12;
116→        --app-rail-bg: #111318;
117→        --app-header-bg: #111318;
118→        --app-content-bg: #161a22;
119→        --app-rail-border: rgba(255, 255, 255, 0.05);
120→        --app-search-bg: rgba(255, 255, 255, 0.05);
121→        --app-search-border: rgba(255, 255, 255, 0.09);
122→        --app-selection-color: #78adff;
123→        --app-selection-on-color: #071225;
124→        --app-selection-surface: color-mix(
125→            in srgb,
126→            var(--app-selection-color) 18%,
127→            transparent
128→        );
129→        --app-selection-surface-strong: color-mix(
130→            in srgb,
131→            var(--app-selection-color) 28%,
132→            transparent
133→        );
134→        --app-selection-border: color-mix(
135→            in srgb,
136→            var(--app-selection-color) 62%,
137→            transparent
138→        );
139→        --app-selection-glow: color-mix(
140→            in srgb,
141→            var(--app-selection-color) 44%,
142→            transparent
143→        );
144→
145→        // Widget surfaces — NO border, surface contrast does the work
146→        // Widgets sit on content-bg (#161a22), so widget-bg is notably lighter
147→        --app-widget-bg: #1e2330;
148→        --app-widget-header-bg: #232840;
149→        --app-widget-border: transparent;
150→        --app-widget-shadow: none;
151→        --app-widget-header-border: rgba(255, 255, 255, 0.05);
152→        --app-card-hover-bg: #252b3a;
153→        --app-separator: rgba(255, 255, 255, 0.14);
154→
155→        // Typography — NOT pure white. Warm graphite-tinted whites
156→        --app-heading-color: #d8dce8;       // soft off-white, not #fff
157→        --app-body-color: #8b93a8;          // muted blue-grey
158→        --app-muted-color: #5c6478;         // dimmed
159→        --app-eyebrow-color: #6b7494;       // eyebrow labels
160→
161→        // Provider accents (slightly brighter for dark bg)
162→        --app-provider-xtream: #818cf8;
163→        --app-provider-stalker: #34d399;
164→        --app-provider-m3u: #fbbf24;
165→
166→        // Hero section
167→        --app-accent-gradient: linear-gradient(
168→            135deg,
169→            rgba(99, 102, 241, 0.12) 0%,
170→            rgba(168, 85, 247, 0.07) 100%
171→        );
172→        --app-hero-surface: rgba(30, 35, 48, 0.9);
173→    }
174→}
