 19→export type WorkspaceCommandScope = 'global' | 'playlist' | 'section';
 20→
 21→export type WorkspaceCommandId =
 22→    | 'global-search'
 23→    | 'playlist-search'
 24→    | 'open-global-favorites'
 25→    | 'open-downloads'
 26→    | 'open-global-recent';
 27→
 28→export interface WorkspaceCommandItem {
 29→    id: WorkspaceCommandId;
 30→    label: string;
 31→    description: string;
 32→    scope: WorkspaceCommandScope;
 33→    enabled: boolean;
 34→}
 35→
 36→export interface WorkspaceCommandSelection {
 37→    commandId: WorkspaceCommandId;
 38→    query: string;
 39→}
 40→
 41→interface WorkspaceCommandPaletteData {
 42→    commands: WorkspaceCommandItem[];
 43→    query?: string;
 44→}
 45→
 46→interface WorkspaceCommandGroup {
 47→    scope: WorkspaceCommandScope;
 48→    items: WorkspaceCommandItem[];
 49→}
 50→
 51→@Component({
 52→    selector: 'app-workspace-command-palette',
 53→    imports: [MatDialogModule, MatIconModule, TranslatePipe],
 54→    templateUrl: './workspace-command-palette.component.html',
 55→    styleUrl: './workspace-command-palette.component.scss',
 56→})
 57→export class WorkspaceCommandPaletteComponent implements AfterViewInit {
 58→    private readonly dialogRef = inject(
 59→        MatDialogRef<
 60→            WorkspaceCommandPaletteComponent,
 61→            WorkspaceCommandSelection | undefined
 62→        >
 63→    );
 64→    private readonly data =
 65→        inject<WorkspaceCommandPaletteData>(MAT_DIALOG_DATA);
 66→
 67→    private readonly queryInputRef =
 68→        viewChild<ElementRef<HTMLInputElement>>('queryInput');
 69→
 70→    readonly query = signal(this.data?.query ?? '');
 71→    readonly selectedIndex = signal(0);
 72→
 73→    readonly filteredCommands = computed(() => {
 74→        const term = this.query().trim().toLowerCase();
 75→        if (!term) {
 76→            return this.data.commands;
 77→        }
 78→
 79→        return this.data.commands.filter((command) => {
 80→            const haystack =
 81→                `${command.label} ${command.description}`.toLowerCase();
 82→            return haystack.includes(term);
 83→        });
 84→    });
 85→
 86→    readonly commandGroups = computed<WorkspaceCommandGroup[]>(() => {
 87→        const commands = this.filteredCommands();
 88→        const grouped: WorkspaceCommandGroup[] = [];
 89→
 90→        const buildGroup = (
 91→            scope: WorkspaceCommandScope
 92→        ): WorkspaceCommandGroup | null => {
 93→            const items = commands.filter((command) => command.scope === scope);
 94→            if (items.length === 0) {
 95→                return null;
 96→            }
 97→            return { scope, items };
 98→        };
 99→
100→        const groups = [
101→            buildGroup('global'),
102→            buildGroup('playlist'),
103→            buildGroup('section'),
104→        ].filter((group): group is WorkspaceCommandGroup => group !== null);
105→
106→        grouped.push(...groups);
107→        return grouped;
108→    });
109→
110→    readonly flatCommands = computed(() =>
111→        this.commandGroups().reduce<WorkspaceCommandItem[]>(
112→            (items, group) => items.concat(group.items),
113→            []
114→        )
115→    );
116→
117→    constructor() {
118→        effect(() => {
119→            const items = this.flatCommands();
120→            if (items.length === 0) {
121→                this.selectedIndex.set(-1);
122→                return;
123→            }
124→
125→            const currentIndex = this.selectedIndex();
126→            if (currentIndex < 0 || currentIndex >= items.length) {
127→                this.selectedIndex.set(0);
128→            }
129→        });
130→    }
131→
132→    ngAfterViewInit(): void {
133→        queueMicrotask(() => {
134→            this.queryInputRef()?.nativeElement.focus();
135→            this.queryInputRef()?.nativeElement.select();
136→        });
137→    }
138→
139→    onQueryInput(event: Event): void {
140→        const target = event.target as HTMLInputElement | null;
141→        this.query.set(target?.value ?? '');
142→    }
143→
144→    onInputKeydown(event: KeyboardEvent): void {
145→        if (event.key === 'ArrowDown') {
146→            event.preventDefault();
147→            this.moveSelection(1);
148→            return;
