  1→/**
  2→ * Resizable Directive Styles
  3→ *
  4→ * A refined, subtle resize handle that provides clear affordance
  5→ * without being visually intrusive. Uses a vertical grip pattern
  6→ * that becomes more prominent on hover/active states.
  7→ */
  8→
  9→// Prevent text selection during resize
 10→body.resizing-active {
 11→    user-select: none !important;
 12→    cursor: col-resize !important;
 13→
 14→    * {
 15→        cursor: col-resize !important;
 16→    }
 17→}
 18→
 19→// Base element styles
 20→.resizable-element {
 21→    // Smooth transition when not actively resizing
 22→    &:not(.is-resizing) {
 23→        transition: width 0.15s ease-out;
 24→    }
 25→
 26→    &.is-resizing {
 27→        transition: none;
 28→    }
 29→}
 30→
 31→// Resize handle base styles
 32→.resize-handle {
 33→    position: absolute;
 34→    top: 0;
 35→    bottom: 0;
 36→    width: 12px;
 37→    z-index: 100;
 38→    cursor: col-resize;
 39→    display: flex;
 40→    align-items: center;
 41→    justify-content: center;
 42→
 43→    // Visual feedback on hover/active
 44→    &::before {
 45→        content: '';
 46→        position: absolute;
 47→        top: 0;
 48→        bottom: 0;
 49→        width: 4px;
 50→        background: transparent;
 51→        transition: background-color 0.2s ease;
 52→        border-radius: 2px;
 53→    }
 54→
 55→    &:hover::before,
 56→    &:active::before {
 57→        background: rgba(255, 255, 255, 0.08);
 58→    }
 59→
 60→    // Position variants
 61→    &--right {
 62→        right: -6px;
 63→
 64→        &::before {
 65→            left: 50%;
 66→            transform: translateX(-50%);
 67→        }
 68→    }
 69→
 70→    &--left {
 71→        left: -6px;
 72→
 73→        &::before {
 74→            right: 50%;
 75→            transform: translateX(50%);
 76→        }
 77→    }
 78→
 79→    // The main visible line
 80→    &__line {
 81→        position: absolute;
 82→        top: 0;
 83→        bottom: 0;
 84→        width: 1px;
 85→        transition: all 0.2s ease;
 86→    }
 87→
 88→    &:hover &__line {
 89→        width: 2px;
 90→        background: rgba(255, 255, 255, 0.25);
 91→        box-shadow: 0 0 8px rgba(255, 255, 255, 0.1);
 92→    }
 93→
 94→    &:active &__line {
 95→        width: 2px;
 96→        background: var(--mdc-theme-primary, #6366f1);
 97→        box-shadow: 0 0 12px rgba(99, 102, 241, 0.3);
 98→    }
 99→
100→    // Grip dots indicator
101→    &__grip {
102→        position: relative;
103→        display: flex;
104→        flex-direction: column;
105→        gap: 4px;
106→        opacity: 0;
107→        transition: opacity 0.2s ease;
108→        z-index: 1;
109→
110→        span {
111→            width: 4px;
112→            height: 4px;
113→            border-radius: 50%;
114→            background: rgba(255, 255, 255, 0.4);
115→            transition: all 0.15s ease;
116→        }
117→    }
118→
119→    &:hover &__grip {
120→        opacity: 1;
121→
122→        span {
123→            background: rgba(255, 255, 255, 0.6);
124→        }
125→    }
126→
127→    &:active &__grip {
128→        opacity: 1;
129→
130→        span {
131→            background: var(--mdc-theme-primary, #6366f1);
132→            transform: scale(1.2);
133→        }
134→    }
135→}
136→
137→// Light theme adjustments (if needed)
138→.light-theme {
139→    .resize-handle {
140→        &::before {
141→            background: transparent;
142→        }
143→
144→        &:hover::before,
145→        &:active::before {
146→            background: rgba(0, 0, 0, 0.04);
147→        }
148→
149→        &:active::before {
150→            background: rgba(0, 0, 0, 0.08);
151→        }
152→
153→        &__line {
154→            background: rgba(0, 0, 0, 0.12);
155→        }
156→
157→        &:hover &__line {
158→            background: rgba(0, 0, 0, 0.25);
159→            box-shadow: 0 0 8px rgba(0, 0, 0, 0.05);
160→        }
161→
162→        &:active &__line {
163→            background: var(--mdc-theme-primary, #6366f1);
164→            box-shadow: 0 0 12px rgba(99, 102, 241, 0.2);
165→        }
166→
167→        &__grip {
168→            span {
169→                background: rgba(0, 0, 0, 0.3);
170→            }
171→        }
172→
173→        &:hover &__grip {
174→            span {
175→                background: rgba(0, 0, 0, 0.5);
176→            }
177→        }
178→    }
179→}
